source = DATA_PATH.read_text(encoding="utf-8")

for slug, data in mod.SERVICES.items():
    if slug not in TEXTS:
        print(f"WARN: missing texts for {slug}")
        continue
    new_stages = []
    for i, stage in enumerate(data["stages"]):
        icon = stage.get("icon") or infer_stage_icon(stage["title"])
        text = TEXTS[slug][i]
        new_stages.append({
            "title": stage["title"],
            "icon": icon,
            "text": text,
        })
    # Build replacement block
    lines = ["        \"stages\": ["]
    for st in new_stages:
        lines.append(f"            {{\"title\": \"{st['title']}\", \"icon\": \"{st['icon']}\", \"text\": \"{st['text']}\"}},")
    lines.append("        ],")
    block = "\n".join(lines)
    pattern = rf'("{re.escape(slug)}": \{{[^}}]*?"stages": \[)(.*?)(\],\s*"faq")'
    m = re.search(pattern, source, re.DOTALL)
    if not m:
        print(f"FAIL: {slug}")
        continue
    source = source[:m.start(2)] + "\n" + "\n".join(lines[1:-1]) + "\n        " + source[m.end(2):]
    print(f"OK: {slug}")

DATA_PATH.write_text(source, encoding="utf-8")
print("Done patching services_data.py")
